mapper.select:
select
(
    select count(*)
    from browsing_history bh
             left join room_info ri on bh.room_id = ri.id
    where bh.is_deleted = 0

        and ri.apartment_id = #{apartmentId}


        and bh.browse_time >= #{startDate}


        and bh.browse_time < date_add(#{endDate}, interval 1 day)

) as browse_count,
(
    select count(*)
    from room_favorite rf
             left join room_info ri on rf.room_id = ri.id
    where rf.is_deleted = 0

        and ri.apartment_id = #{apartmentId}


        and rf.create_time >= #{startDate}


        and rf.create_time < date_add(#{endDate}, interval 1 day)

) as favorite_count,
(
    select count(*)
    from view_appointment va
    where va.is_deleted = 0

        and va.apartment_id = #{apartmentId}


        and va.create_time >= #{startDate}


        and va.create_time < date_add(#{endDate}, interval 1 day)

) as appointment_count,
(
    select count(*)
    from lease_order lo
    where lo.is_deleted = 0

        and lo.apartment_id = #{apartmentId}


        and lo.create_time >= #{startDate}


        and lo.create_time < date_add(#{endDate}, interval 1 day)

) as order_count
